import React, { useState, useEffect } from 'react';
import { clientAPI } from '../../services/clientAPI';

export default function ClientQuestionnaire() {
  const [questionnaire, setQuestionnaire] = useState(null);
  const [reponses, setReponses] = useState({});
  const [step, setStep] = useState(0);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(null);

  useEffect(() => {
    clientAPI.getQuestionnaire()
      .then((r) => { setQuestionnaire(r.data); setReponses(r.data.reponses_existantes || {}); })
      .catch(() => setError('Impossible de charger le questionnaire'))
      .finally(() => setLoading(false));
  }, []);

  const questions = questionnaire?.questions || [];
  const current = questions[step];
  const answered = Object.keys(reponses).length;

  const setReponse = (id, val) => setReponses((r) => ({ ...r, [id]: val }));

  const handleSubmit = async () => {
    setSubmitting(true); setError('');
    try {
      const body = Object.entries(reponses).map(([id, val]) => ({
        id_question: parseInt(id, 10),
        valeur: String(val),
      }));
      const res = await clientAPI.soumettreQuestionnaire(body);
      setSuccess(res.data);
    } catch (e) {
      setError(e.response?.data?.detail || 'Erreur lors de la soumission');
    } finally { setSubmitting(false); }
  };

  if (loading) return <div className="cl-loader"><div className="cl-spinner" /></div>;
  if (error && !questionnaire) return (
    <div className="cl-empty" style={{ color: 'var(--c-red)' }}>
      <i className="ti ti-alert-circle" /><p>{error}</p>
    </div>
  );

  if (success) {
    return (
      <div className="cl-page">
        <div className="cl-success">
          <i className="ti ti-circle-check" style={{ fontSize: 20 }} />
          Questionnaire soumis avec succès !
        </div>
        <div className="cl-devis-card">
          <div style={{ fontSize: 10, letterSpacing: '0.12em', color: 'var(--c-text3)', fontWeight: 600, marginBottom: 12 }}>
            SCORE OBTENU
          </div>
          <div className="cl-devis-prime">
            {success.score_global}<span> /100</span>
          </div>
          <div className="cl-devis-label">SCORE DE RISQUE CYBER</div>
          <div style={{ marginTop: 12, fontSize: 14, color: '#A78BFA', fontWeight: 600 }}>
            Niveau: {success.niveau_risque}
          </div>
        </div>
      </div>
    );
  }

  if (!current) return null;

  const progress = ((step + 1) / questions.length) * 100;

  return (
    <div className="cl-page">
      {/* Progress bar */}
      <div className="cl-q-progress-wrap">
        <span className="cl-q-progress-label">{step + 1} / {questions.length}</span>
        <div className="cl-q-progress-bar">
          <div className="cl-q-progress-fill" style={{ width: `${progress}%` }} />
        </div>
        <span className="cl-q-progress-label">{answered} répondu(s)</span>
      </div>

      {error && <div style={{ color: 'var(--c-red)', fontSize: 13 }}>{error}</div>}

      {/* Question card */}
      <div className="cl-q-card">
        {current.categorie && (
          <div className="cl-q-categorie">{current.categorie}</div>
        )}
        <div className="cl-q-text">{current.texte}</div>

        {current.type === 'boolean' && (
          <div className="cl-options">
            {['oui', 'non'].map((v) => (
              <button
                key={v}
                className={`cl-option-btn ${reponses[current.id_question] === v ? 'cl-option-btn--selected' : ''}`}
                onClick={() => setReponse(current.id_question, v)}
              >
                {v === 'oui' ? 'Oui' : 'Non'}
              </button>
            ))}
          </div>
        )}

        {current.type === 'scale' && (
          <div>
            <div className="cl-scale-row">
              {[1, 2, 3, 4, 5].map((v) => (
                <button
                  key={v}
                  className={`cl-scale-btn ${reponses[current.id_question] === String(v) ? 'cl-scale-btn--selected' : ''}`}
                  onClick={() => setReponse(current.id_question, String(v))}
                >
                  {v}
                </button>
              ))}
            </div>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: 6 }}>
              <span style={{ fontSize: 10, color: 'var(--c-text3)', letterSpacing: '0.08em' }}>FAIBLE</span>
              <span style={{ fontSize: 10, color: 'var(--c-text3)', letterSpacing: '0.08em' }}>ÉLEVÉ</span>
            </div>
          </div>
        )}

        {current.type === 'choix_multiple' && current.options && (
          <div className="cl-options">
            {current.options.map((opt) => (
              <button
                key={opt}
                className={`cl-option-btn ${reponses[current.id_question] === opt ? 'cl-option-btn--selected' : ''}`}
                onClick={() => setReponse(current.id_question, opt)}
              >
                {opt}
              </button>
            ))}
          </div>
        )}

        {current.type === 'text' && (
          <textarea
            className="cl-text-input"
            rows={3}
            value={reponses[current.id_question] || ''}
            onChange={(e) => setReponse(current.id_question, e.target.value)}
            placeholder="Votre réponse..."
          />
        )}
      </div>

      {/* Navigation */}
      <div className="cl-q-nav">
        <button
          className="cl-btn-ghost"
          onClick={() => setStep((s) => Math.max(0, s - 1))}
          disabled={step === 0}
        >
          <i className="ti ti-arrow-left" /> Précédent
        </button>

        {step < questions.length - 1 ? (
          <button className="cl-btn-primary" onClick={() => setStep((s) => s + 1)}>
            Suivant <i className="ti ti-arrow-right" />
          </button>
        ) : (
          <button className="cl-btn-primary" onClick={handleSubmit} disabled={submitting}>
            {submitting ? 'Envoi...' : <><i className="ti ti-send" /> Soumettre</>}
          </button>
        )}
      </div>
    </div>
  );
}
